from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triple objects describing an artist (or related entity)
    into a single fluent English sentence.
    """
    if not triples:
        return ""

    # Assume all triples refer to the same main subject (the first one's subject)
    main_subject = triples[0].subject

    # Gather information by predicate
    genre = None
    associated = []
    other_clauses = []

    def clean_obj(obj: str) -> str:
        return obj.strip('"')

    for t in triples:
        obj = clean_obj(t.object)
        p = t.predicate

        if p == "genre" and not genre:
            genre = obj
        elif p == "associatedBand/associatedMusicalArtist":
            associated.append(obj)
        else:
            # map remaining predicates to short phrases (without the subject)
            if p == "background":
                other_clauses.append(f"is a {obj}")
            elif p == "instrument":
                other_clauses.append(f"plays the {obj}")
            elif p == "origin":
                other_clauses.append(f"originates from {obj}")
            elif p == "birthDate":
                other_clauses.append(f"was born on {obj}")
            elif p == "birthPlace":
                other_clauses.append(f"was born in {obj}")
            elif p == "birthYear":
                other_clauses.append(f"was born in {obj}")
            elif p == "occupation":
                other_clauses.append(f"is a {obj}")
            elif p == "recordLabel":
                other_clauses.append(f"is signed to {obj}")
            elif p == "deathPlace":
                other_clauses.append(f"died in {obj}")
            elif p == "deathDate":
                other_clauses.append(f"died on {obj}")
            elif p == "nationality":
                other_clauses.append(f"is {obj}")
            elif p == "professionalField":
                other_clauses.append(f"works in {obj}")
            elif p in ("language", "officialLanguage"):
                other_clauses.append(f"speaks {obj}")
            elif p == "capital":
                other_clauses.append(f"has capital {obj}")
            elif p == "currency":
                other_clauses.append(f"uses the {obj}")
            elif p == "populationDensity":
                other_clauses.append(f"has a population density of {obj}")
            else:
                # generic fallback
                pred_readable = p.replace("_", " ")
                other_clauses.append(f"{pred_readable} {obj}")

    # Build the main clause
    parts = []

    if genre:
        parts.append(f"{main_subject} is a {genre.lower()} musician")
    else:
        parts.append(main_subject)

    if associated:
        assoc_str = ", ".join(associated[:-1]) + (" and " if len(associated) > 1 else "") + associated[-1] if len(associated) > 1 else associated[0]
        parts.append(f"associated with {assoc_str}")

    if other_clauses:
        # join other clauses with commas, last with 'and'
        if len(other_clauses) == 1:
            parts.append(other_clauses[0])
        else:
            other_body = ", ".join(other_clauses[:-1]) + ", and " + other_clauses[-1]
            parts.append(other_body)

    # Combine all parts into a single fluent sentence
    sentence = ", ".join(parts).rstrip(".") + "."

    return sentence

# EVOLVE-BLOCK-END

